mapper.select:
select substr(add_time,1,10) as day, count(*) as newUsers from litemall_user where deleted = 0
and substr(add_time,1,10) >= #{startDate}
and substr(add_time,1,10) <= #{endDate}
group by substr(add_time,1,10) order by day

select substr(last_login_time,1,10) as day, count(distinct id) as dau from litemall_user where deleted = 0 and last_login_time is not null
and substr(last_login_time,1,10) >= #{startDate}
and substr(last_login_time,1,10) <= #{endDate}
group by substr(last_login_time,1,10) order by day

SELECT event_type AS eventType, COUNT(*) AS count FROM litemall_tracker_event WHERE deleted = 0
AND DATE(server_time) >= #{startDate}
AND DATE(server_time) <= #{endDate}
GROUP BY event_type ORDER BY count DESC

SELECT DATE(server_time) AS day, SUM(CASE WHEN event_type = 'page_view' THEN 1 ELSE 0 END) AS page_view, SUM(CASE WHEN event_type = 'goods_view' THEN 1 ELSE 0 END) AS goods_view, SUM(CASE WHEN event_type = 'add_cart' THEN 1 ELSE 0 END) AS add_cart, SUM(CASE WHEN event_type = 'order_create' THEN 1 ELSE 0 END) AS order_create, SUM(CASE WHEN event_type = 'order_pay' THEN 1 ELSE 0 END) AS order_pay FROM litemall_tracker_event WHERE deleted = 0
AND DATE(server_time) >= #{startDate}
AND DATE(server_time) <= #{endDate}
GROUP BY DATE(server_time) ORDER BY day

SELECT
    page_route AS pageRoute,
    COUNT(*) AS count,
    COUNT(DISTINCT user_id) AS uniqueUsers
FROM litemall_tracker_event
WHERE deleted = 0
AND event_type = #{eventType}

    AND DATE(server_time) >= #{startDate}


    AND DATE(server_time) <= #{endDate}

GROUP BY page_route
ORDER BY count DESC
LIMIT #{limit}

SELECT COUNT(*) AS totalPush, SUM(CASE WHEN view_time IS NOT NULL THEN 1 ELSE 0 END) AS viewedPush, SUM(CASE WHEN order_id IS NOT NULL THEN 1 ELSE 0 END) AS orderedPush FROM litemall_push_log WHERE deleted = 0
AND DATE(send_time) >= #{startDate}
AND DATE(send_time) <= #{endDate}

SELECT COALESCE(SUM(actual_price), 0) as totalRevenue, COUNT(id) as totalOrders, ROUND(COALESCE(AVG(actual_price), 0), 0) as avgOrderPrice, COUNT(DISTINCT user_id) as totalCustomers FROM litemall_order WHERE deleted = 0 AND order_status IN (401, 402)
AND DATE_FORMAT(pay_time, '%Y-%m') >= #{startMonth}
AND DATE_FORMAT(pay_time, '%Y-%m') <= #{endMonth}

SELECT DATE_FORMAT(pay_time, '%Y-%m') as month, COALESCE(SUM(actual_price), 0) as revenue, COUNT(id) as orders FROM litemall_order WHERE deleted = 0 AND order_status IN (401, 402)
AND DATE_FORMAT(pay_time, '%Y-%m') >= #{startMonth}
AND DATE_FORMAT(pay_time, '%Y-%m') <= #{endMonth}
GROUP BY DATE_FORMAT(pay_time, '%Y-%m') ORDER BY month

SELECT m.month, m.orders, m.revenue, COALESCE(r.refund, 0) as refund FROM ( SELECT DATE_FORMAT(o.pay_time, '%Y-%m') as month, COUNT(o.id) as orders, SUM(o.actual_price) as revenue FROM litemall_order o WHERE o.deleted = 0 AND o.order_status IN (401, 402)
AND DATE_FORMAT(o.pay_time, '%Y-%m') >= #{startMonth}
AND DATE_FORMAT(o.pay_time, '%Y-%m') <= #{endMonth}
GROUP BY DATE_FORMAT(o.pay_time, '%Y-%m') ) m LEFT JOIN ( SELECT DATE_FORMAT(a.update_time, '%Y-%m') as refund_month, SUM(a.amount) as refund FROM litemall_aftersale a WHERE a.deleted = 0 AND a.status = 2 GROUP BY DATE_FORMAT(a.update_time, '%Y-%m') ) r ON m.month = r.refund_month ORDER BY m.month

SELECT cs.id as sceneId, cs.name, COUNT(DISTINCT o.id) as orders, COALESCE(SUM(og.number * og.price), 0) as amount FROM clothing_scene cs LEFT JOIN clothing_goods_scene cgs ON cs.id = cgs.scene_id LEFT JOIN litemall_goods g ON cgs.goods_id = g.id AND g.deleted = 0 LEFT JOIN litemall_order_goods og ON g.id = og.goods_id LEFT JOIN litemall_order o ON og.order_id = o.id AND o.deleted = 0 AND o.order_status IN (401, 402)
AND DATE(o.pay_time) >= #{startDate}
AND DATE(o.pay_time) <= #{endDate}
WHERE cs.deleted = 0 GROUP BY cs.id, cs.name ORDER BY amount DESC

SELECT c.id as categoryId, c.name, COUNT(DISTINCT g.id) as goodsCount, COUNT(DISTINCT o.id) as orders, COALESCE(SUM(og.number * og.price), 0) as amount FROM litemall_category c LEFT JOIN litemall_goods g ON c.id = g.category_id AND g.deleted = 0 LEFT JOIN litemall_order_goods og ON g.id = og.goods_id LEFT JOIN litemall_order o ON og.order_id = o.id AND o.deleted = 0 AND o.order_status IN (401, 402)
AND DATE(o.pay_time) >= #{startDate}
AND DATE(o.pay_time) <= #{endDate}
WHERE c.deleted = 0 AND c.level = 'L2' GROUP BY c.id, c.name HAVING amount > 0 ORDER BY amount DESC LIMIT 10
